{
  "name": "Low-Income Home Energy Assistance Program (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly household income at or below 60% of Rhode Island State Median Income (SMI). FFY2026 limits (from Westbay CAP example, applicable statewide): Household of 1: $3,521/month ($42,252/year); 2: $4,604/month ($55,252/year); 3: $5,687/month ($68,253/year). Full table available in official FFY2026 Eligibility Chart PDF. Counts gross income including wages, self-employment (60%), unemployment, Social Security, alimony, etc.[2][5][7]",
    "asset_limits": "No asset or resource limits; resources are not counted.[4]",
    "other_requirements": ["U.S. citizen or lawfully present immigrant (mixed-status households eligible based on eligible members),[4]", "Responsible for heating costs (renters or homeowners),[3]", "No requirement for unpaid bill or public assistance.[3]"]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time grant paid directly to utility or fuel company for heating costs. Minimum $75, maximum $1285 (FFY2025; 2026 similar). Crisis grants for emergencies like shutoffs or broken heaters. Amounts based on income, household size, fuel type, minimum delivery.[2][5][7]",
    "varies_by": "household_size|priority_tier"
  },
  "application": {
    "methods": ["Online: https://dhs.ri.gov/programs-and-services/energy-assistance-programs-heating/low-income-home-energy-assistance-program (state portal) or local CAP agency portals,[3][6][8]", "Phone: Local CAP agencies e.g. CAPP (401)-273-2000, EBCAP 401-437-1000 ext. 6606,[6][8]", "In-person or dropbox: Local Community Action Program (CAP) agencies,[3][6]", "Mail: To local CAP agency; renewal forms mailed in September.[3][7]"],
    "processing_time": "3-5 business days for initial review; staff contacts for more info.[6]",
    "waitlist": "Funding limited; applications may close early if funds exhausted. Priority for shutoff/termination notices.[1][6]",
    "forms": ["Renewal Application (mailed to prior recipients), No Income Form, Other Income Form, Rental Income Form, Support Letter, Landlord Information Form, First Appeal Request Form (for denials).[3][7]"],
    "documents": ["Social Security Card (applicant and all household members), Government-issued photo ID (driver's license, state ID, passport), Proof of income (3 months preferred), Gas/electric bill or fuel ticket, Proof of residency.[2][6][7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all RI households meeting criteria.",
    "regional_variations": "Administered uniformly by RI DHS but applications processed by local Community Action Program (CAP) agencies with potential differences in intake (e.g., dropbox at CAPP, online at EBCAP/Westbay). Wait times may vary by agency funding.[3][6][7][8]",
    "offices_or_providers": ["Local CAP agencies: CAPP (Providence, 401-273-2000), Westbay CAP, EBCAP (401-437-1000), others via DHS locator.[3][6][7][8]"]
  },
  "official_source": "https://dhs.ri.gov/programs-and-services/energy-assistance-programs-heating/low-income-home-energy-assistance-program",
  "gotchas": ["No cooling assistance in RI,[1]", "Crisis only for true emergencies (e.g., shutoff, broken furnace),[1]", "Must apply early; funds run out (season Oct-May, renewals Sept),[1][3]", "New applicants prefer in-person; online requires email verification within 30 min,[3][6]", "Gross income used (no deductions except self-employment 60%), roommates count as household if sharing utilities,[1][2]", "Weatherization separate, requires LIHEAP eligibility first.[5]"],
  "data_shape_notes": "Income at 60% SMI (table by household size, FFY yearly updates); no assets; CAP agencies handle apps statewide with local contacts; priority tiers for crisis; grants scale by income/size/fuel."
}

{
  "name": "RI SHIP (State Health Insurance Assistance Program)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare-eligible individuals, their families, and caregivers, including those with limited incomes, under age 65 with disabilities, and dually eligible for Medicare and Medicaid[1][3]",
    "asset_limits": "No asset limits or tests apply[1]",
    "other_requirements": ["Must be Medicare-eligible or a family member/caregiver of a Medicare beneficiary[3][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling and assistance on Medicare options (Parts A, B, C, D, Medigap), enrollment in prescription drug plans and health plans, applications for low-income programs (Medicaid, Medicare Savings Programs, Extra Help/LIS), resolving Medicare problems, education on rights/protections, and outreach presentations; provided by trained, independent counselors and volunteers[1][3][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": [
      "Phone: 1-888-884-8721 (main), TTY: 401-462-0740, Providence: 2-1-1 or 401-462-4444 (POINT), Northern RI: 401-349-5760 x2635[5][8]",
      "In-person or remote assistance via local RI SHIP locations (e.g., Office of Healthy Aging, 25 Howard Ave, Building 57, Cranston RI 02920)[4][5]",
      "Website for info and remote assistance: oha.ri.gov (Office of Healthy Aging site implied via PDFs)[3][5]"
    ],
    "processing_time": "Not specified in available data",
    "waitlist": null,
    "forms": ["RI SHIP Client Confidentiality Agreement / Release of Information Form (required for services)[3]"],
    "documents": ["No specific documents listed for initial contact; form may require basic info for confidentiality/release; prepare Medicare info, income details if applying for assistance programs[3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Contact numbers vary by region (e.g., Providence via 2-1-1, Northern RI specific line); services delivered statewide via Office of Healthy Aging and local partners, no noted differences in benefits or wait times[4][5]",
    "offices_or_providers": ["Office of Healthy Aging (OHA), 25 Howard Ave, Building 57, Cranston RI 02920; local sites in Providence, Northern RI[4][5]"]
  },
  "official_source": "https://oha.ri.gov (Office of Healthy Aging, RI SHIP sponsor)",
  "gotchas": [
    "Counselors/volunteers are independent and not affiliated with insurance/pharma—ensures unbiased advice, but they only assist with applications upon request, do not sell plans[3]",
    "Services require signing Client Confidentiality Agreement/Release form[3]",
    "Regional phone lines exist (e.g., Northern RI, Providence)—using the wrong one may delay local help[5]",
    "No income/asset test, but helps apply for programs that do have them (e.g., Extra Help, MSP)[1]"
  ],
  "data_shape_notes": "no income/asset test; counseling-only service (not financial aid); regionally varied contact points but uniform statewide benefits; volunteer/staff delivered via state Office of Healthy Aging"
}

